use criterion::{Criterion, black_box, criterion_group, criterion_main};
use rublock::queue_solver::QueueSolverState;
use rublock::solver::{Puzzle, SolverState};

// Generated by `cargo run --bin gen_bench_puzzles`
const PUZZLES: &[([u8; 6], [u8; 6])] = &[
    // propagation-only
    ([7, 0, 4, 7, 4, 3], [0, 10, 4, 1, 0, 0]),
    // propagation-only
    ([0, 0, 4, 10, 0, 9], [0, 8, 0, 6, 7, 3]),
    // propagation-only
    ([4, 0, 9, 0, 9, 1], [0, 3, 4, 7, 5, 8]),
    // propagation-only
    ([2, 8, 4, 6, 5, 6], [0, 2, 3, 0, 4, 1]),
    // propagation-only
    ([6, 2, 0, 0, 5, 5], [4, 10, 0, 1, 3, 5]),
    // needs backtracking
    ([7, 4, 4, 1, 4, 0], [7, 7, 0, 3, 4, 4]),
    // needs backtracking
    ([3, 2, 2, 3, 5, 1], [7, 0, 5, 0, 0, 0]),
    // needs backtracking
    ([0, 0, 0, 1, 4, 5], [2, 3, 1, 0, 2, 4]),
    // needs backtracking
    ([5, 0, 0, 0, 3, 7], [1, 4, 1, 0, 0, 9]),
    // needs backtracking
    ([4, 4, 4, 10, 3, 4], [4, 6, 7, 6, 4, 1]),
];

fn bench_solver(c: &mut Criterion) {
    let mut group = c.benchmark_group("solve");

    for (i, &(row_targets, col_targets)) in PUZZLES.iter().enumerate() {
        group.bench_function(format!("basic/{i}"), |b| {
            b.iter(|| {
                assert_eq!(
                    SolverState::new(black_box(Puzzle::new(row_targets, col_targets)))
                        .count_solutions(2),
                    1
                );
            })
        });

        group.bench_function(format!("queue/{i}"), |b| {
            b.iter(|| {
                assert_eq!(
                    QueueSolverState::new(black_box(Puzzle::new(row_targets, col_targets)))
                        .count_solutions(2),
                    1
                );
            })
        });
    }

    group.finish();
}

criterion_group!(benches, bench_solver);
criterion_main!(benches);
